PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:8', 50, 8, 26, 518, 4638, 'تَبْصِرَةً وَّذِكْرٰى لِكُلِّ عَبْدٍ مُّنِيْبٍ ', ' untuk menjadi pelajaran dan pengingat bagi setiap hamba yang kembali (tunduk kepada Allah). ', '', 'https://everyayah.com/data/Alafasy_128kbps/050008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:9', 50, 9, 26, 518, 4639, 'وَنَزَّلْنَا مِنَ السَّمَاۤءِ مَاۤءً مُّبٰرَكًا فَاَنْۢبَتْنَا بِهٖ جَنّٰتٍ وَّحَبَّ الْحَصِيْدِۙ', ' Kami turunkan dari langit air yang diberkahi, lalu Kami tumbuhkan dengannya kebun-kebun dan biji-bijian yang dapat dipanen. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:10', 50, 10, 26, 518, 4640, 'وَالنَّخْلَ بٰسِقٰتٍ لَّهَا طَلْعٌ نَّضِيْدٌۙ', ' Begitu pula pohon-pohon kurma yang tinggi yang mayangnya bersusun-susun ', '', 'https://everyayah.com/data/Alafasy_128kbps/050010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:11', 50, 11, 26, 518, 4641, 'رِّزْقًا لِّلْعِبَادِۙ وَاَحْيَيْنَا بِهٖ بَلْدَةً مَّيْتًاۗ  كَذٰلِكَ الْخُرُوْجُ  ', ' sebagai rezeki bagi hamba-hamba (Kami). Kami hidupkan pula dengan (air) itu negeri yang mati (tandus). Seperti itulah terjadinya kebangkitan (dari kubur). ', '', 'https://everyayah.com/data/Alafasy_128kbps/050011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:12', 50, 12, 26, 518, 4642, 'كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوْحٍ وَّاَصْحٰبُ الرَّسِّ وَثَمُوْدُ ', ' Sebelum mereka, kaum Nuh, penduduk Rass, dan (kaum) Samud telah mendustakan (rasul-rasul).', '', 'https://everyayah.com/data/Alafasy_128kbps/050012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:13', 50, 13, 26, 518, 4643, 'وَعَادٌ وَّفِرْعَوْنُ وَاِخْوَانُ لُوْطٍۙ', '(Demikian juga kaum) ‘Ad, Fir‘aun, kaum Lut, ', '', 'https://everyayah.com/data/Alafasy_128kbps/050013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:14', 50, 14, 26, 518, 4644, 'وَّاَصْحٰبُ الْاَيْكَةِ وَقَوْمُ تُبَّعٍۗ كُلٌّ كَذَّبَ الرُّسُلَ فَحَقَّ وَعِيْدِ', ' penduduk Aikah, dan kaum Tubba‘. Semuanya telah mendustakan rasul-rasul, maka berlakulah ancaman-Ku (atas mereka). ', '', 'https://everyayah.com/data/Alafasy_128kbps/050014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:15', 50, 15, 26, 518, 4645, 'اَفَعَيِيْنَا بِالْخَلْقِ الْاَوَّلِۗ بَلْ هُمْ فِيْ لَبْسٍ مِّنْ خَلْقٍ جَدِيْدٍ ࣖ', 'Apakah Kami letih dengan penciptaan yang pertama? (Sama sekali tidak,) bahkan mereka dalam keadaan ragu tentang penciptaan yang baru. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:16', 50, 16, 26, 519, 4646, 'وَلَقَدْ خَلَقْنَا الْاِنْسَانَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهٖ نَفْسُهٗ ۖوَنَحْنُ اَقْرَبُ اِلَيْهِ مِنْ حَبْلِ الْوَرِيْدِ ', 'Sungguh, Kami benar-benar telah menciptakan manusia dan mengetahui apa yang dibisikkan oleh dirinya. Kami lebih dekat kepadanya daripada urat lehernya.', '', 'https://everyayah.com/data/Alafasy_128kbps/050016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:17', 50, 17, 26, 519, 4647, 'اِذْ يَتَلَقَّى الْمُتَلَقِّيٰنِ عَنِ الْيَمِيْنِ وَعَنِ الشِّمَالِ قَعِيْدٌ ', '(Ingatlah) ketika dua malaikat mencatat (perbuatannya). Yang satu duduk di sebelah kanan dan yang lain di sebelah kiri. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:18', 50, 18, 26, 519, 4648, 'مَا يَلْفِظُ مِنْ قَوْلٍ اِلَّا لَدَيْهِ رَقِيْبٌ عَتِيْدٌ ', 'Tidak ada suatu kata pun yang terucap, melainkan ada di sisinya malaikat pengawas yang selalu siap (mencatat). ', '', 'https://everyayah.com/data/Alafasy_128kbps/050018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:19', 50, 19, 26, 519, 4649, 'وَجَاۤءَتْ سَكْرَةُ الْمَوْتِ بِالْحَقِّ ۗذٰلِكَ مَا كُنْتَ مِنْهُ تَحِيْدُ', ' (Seketika itu) datanglah sakratulmautdengan sebenar-benarnya. Itulah yang dahulu hendak engkau hindari. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:20', 50, 20, 26, 519, 4650, 'وَنُفِخَ فِى الصُّوْرِۗ ذٰلِكَ يَوْمُ الْوَعِيْدِ ', ' Ditiuplah sangkakala. Itulah hari yang diancamkan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:21', 50, 21, 26, 519, 4651, 'وَجَاۤءَتْ كُلُّ نَفْسٍ مَّعَهَا سَاۤىِٕقٌ وَّشَهِيْدٌ ', ' Lalu, setiap orang akan datang bersama (malaikat) penggiring dan saksi. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:22', 50, 22, 26, 519, 4652, 'لَقَدْ كُنْتَ فِيْ غَفْلَةٍ مِّنْ هٰذَا فَكَشَفْنَا عَنْكَ غِطَاۤءَكَ فَبَصَرُكَ الْيَوْمَ حَدِيْدٌ ', 'Sungguh, kamu dahulu benar-benar lalai tentang (peristiwa) ini, maka Kami singkapkan penutup matamu, sehingga penglihatanmu pada hari ini sangat tajam. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:23', 50, 23, 26, 519, 4653, 'وَقَالَ قَرِيْنُهٗ هٰذَا مَا لَدَيَّ عَتِيْدٌۗ', '(Malaikat) yang menyertainya berkata, “Inilah (catatan perbuatan) yang ada padaku.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/050023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:24', 50, 24, 26, 519, 4654, 'اَلْقِيَا فِيْ جَهَنَّمَ كُلَّ كَفَّارٍ عَنِيْدٍ ', '(Allah berfirman,) “Lemparkanlah olehmu berdua ke dalam (neraka) Jahanam semua orang yang sangat ingkar, keras kepala,', '', 'https://everyayah.com/data/Alafasy_128kbps/050024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:25', 50, 25, 26, 519, 4655, 'مَنَّاعٍ لِّلْخَيْرِ مُعْتَدٍ مُّرِيْبٍۙ', 'sangat enggan melakukan kebajikan, melampaui batas, bersikap ragu-ragu,', '', 'https://everyayah.com/data/Alafasy_128kbps/050025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:26', 50, 26, 26, 519, 4656, ' ۨالَّذِيْ جَعَلَ مَعَ اللّٰهِ اِلٰهًا اٰخَرَ فَاَلْقِيٰهُ فِى الْعَذَابِ الشَّدِيْدِ ', '(dan) yang mempersekutukan Allah dengan tuhan lain. Maka, lemparkanlah dia ke dalam azab yang keras.”', '', 'https://everyayah.com/data/Alafasy_128kbps/050026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:27', 50, 27, 26, 519, 4657, '۞ قَالَ قَرِيْنُهٗ رَبَّنَا مَآ اَطْغَيْتُهٗ وَلٰكِنْ كَانَ فِيْ ضَلٰلٍۢ بَعِيْدٍ ', '(Setan) yang menyertainya berkata (pula), “Ya Tuhan kami, aku tidak menyesatkannya, tetapi dia sendiri yang berada dalam kesesatan yang jauh.”', '', 'https://everyayah.com/data/Alafasy_128kbps/050027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:28', 50, 28, 26, 519, 4658, 'قَالَ لَا تَخْتَصِمُوْا لَدَيَّ وَقَدْ قَدَّمْتُ اِلَيْكُمْ بِالْوَعِيْدِ ', '(Allah) berfirman, “Janganlah bertengkar di hadapan-Ku dan sungguh, dahulu Aku telah memberikan ancaman kepadamu. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:29', 50, 29, 26, 519, 4659, 'مَا يُبَدَّلُ الْقَوْلُ لَدَيَّ وَمَآ اَنَا۠ بِظَلَّامٍ لِّلْعَبِيْدِ ࣖ ', 'Keputusan-Ku tidak dapat diubah dan Aku (sama sekali) tidak menzalimi hamba-hamba-Ku.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/050029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:30', 50, 30, 26, 519, 4660, 'يَوْمَ نَقُوْلُ لِجَهَنَّمَ هَلِ امْتَلَـْٔتِ وَتَقُوْلُ هَلْ مِنْ مَّزِيْدٍ ', '(Ingatlah) pada hari (ketika) Kami bertanya kepada (neraka) Jahanam, “Apakah kamu sudah penuh?” Ia menjawab, “Adakah tambahan lagi?” ', '', 'https://everyayah.com/data/Alafasy_128kbps/050030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:31', 50, 31, 26, 519, 4661, 'وَاُزْلِفَتِ الْجَنَّةُ لِلْمُتَّقِيْنَ غَيْرَ بَعِيْدٍ ', 'Adapun surga didekatkan kepada orang-orang yang bertakwa pada tempat yang tidak jauh (dari mereka). ', '', 'https://everyayah.com/data/Alafasy_128kbps/050031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:32', 50, 32, 26, 519, 4662, 'هٰذَا مَا تُوْعَدُوْنَ لِكُلِّ اَوَّابٍ حَفِيْظٍۚ', '(Dikatakan kepada mereka,) “Inilah yang dijanjikan kepadamu, (yaitu) kepada setiap hamba yang bertobat lagi patuh.', '', 'https://everyayah.com/data/Alafasy_128kbps/050032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:33', 50, 33, 26, 519, 4663, 'مَنْ خَشِيَ الرَّحْمٰنَ بِالْغَيْبِ وَجَاۤءَ بِقَلْبٍ مُّنِيْبٍۙ', '(Dialah) orang yang takut kepada Zat Yang Maha Pengasih (sekalipun) dia tidak melihat-Nya dan dia datang (menghadap Allah) dengan hati yang bertobat.', '', 'https://everyayah.com/data/Alafasy_128kbps/050033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:34', 50, 34, 26, 519, 4664, ' ۨادْخُلُوْهَا بِسَلٰمٍ ۗذٰلِكَ يَوْمُ الْخُلُوْدِ ', ' Masuklah ke (dalam surga) dengan aman dan damai. Itulah hari yang abadi.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/050034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:35', 50, 35, 26, 519, 4665, 'لَهُمْ مَّا يَشَاۤءُوْنَ فِيْهَا وَلَدَيْنَا مَزِيْدٌ ', 'Mereka di dalamnya memperoleh apa yang mereka kehendaki dan pada Kami masih ada lagi tambahan (nikmat).', '', 'https://everyayah.com/data/Alafasy_128kbps/050035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:36', 50, 36, 26, 520, 4666, 'وَكَمْ اَهْلَكْنَا قَبْلَهُمْ مِّنْ قَرْنٍ هُمْ اَشَدُّ مِنْهُمْ بَطْشًا فَنَقَّبُوْا فِى الْبِلَادِۗ هَلْ مِنْ مَّحِيْصٍ ', ' Betapa banyak umat sebelumnya (kaum kafir Quraisy) yang telah Kami binasakan! Mereka itu lebih hebat kekuatannya daripada (kaum kafir Quraisy) itu, sehingga mampu menjelajah (dan mengamati) beberapa negeri. Adakah tempat pelarian (bagi mereka dari kebinasaan)?', '', 'https://everyayah.com/data/Alafasy_128kbps/050036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:37', 50, 37, 26, 520, 4667, 'اِنَّ فِيْ ذٰلِكَ لَذِكْرٰى لِمَنْ كَانَ لَهٗ قَلْبٌ اَوْ اَلْقَى السَّمْعَ وَهُوَ شَهِيْدٌ ', ' Sesungguhnya pada yang demikian itu pasti terdapat peringatan bagi orang-orang yang mempunyai hati atau yang menggunakan pendengarannya dan dia menyaksikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/050037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:38', 50, 38, 26, 520, 4668, 'وَلَقَدْ خَلَقْنَا السَّمٰوٰتِ وَالْاَرْضَ وَمَا بَيْنَهُمَا فِيْ سِتَّةِ اَيَّامٍۖ وَّمَا مَسَّنَا مِنْ لُّغُوْبٍ ', 'Sungguh, Kami benar-benar telah menciptakan langit, bumi, dan apa yang ada antara keduanya dalam enam masa dan Kami tidak merasa letih sedikit pun.', '', 'https://everyayah.com/data/Alafasy_128kbps/050038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:39', 50, 39, 26, 520, 4669, 'فَاصْبِرْ عَلٰى مَا يَقُوْلُوْنَ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوْعِ الشَّمْسِ وَقَبْلَ الْغُرُوْبِ ۚ', ' Maka, bersabarlah engkau (Nabi Muhammad) terhadap apa yang mereka katakan dan bertasbihlah seraya bertahmid (memuji) Tuhanmu sebelum terbit dan terbenamnya matahari.', '', 'https://everyayah.com/data/Alafasy_128kbps/050039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:40', 50, 40, 26, 520, 4670, 'وَمِنَ الَّيْلِ فَسَبِّحْهُ وَاَدْبَارَ السُّجُوْدِ ', 'Bertasbihlah pula kepada-Nya pada sebagian malam hari dan setiap selesai salat.', '', 'https://everyayah.com/data/Alafasy_128kbps/050040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:41', 50, 41, 26, 520, 4671, 'وَاسْتَمِعْ يَوْمَ يُنَادِ الْمُنَادِ مِنْ مَّكَانٍ قَرِيْبٍ ', ' Dengarkanlah (seruan) pada hari (ketika malaikat) penyeru memanggil dari tempat yang dekat!', '', 'https://everyayah.com/data/Alafasy_128kbps/050041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:42', 50, 42, 26, 520, 4672, 'يَوْمَ يَسْمَعُوْنَ الصَّيْحَةَ بِالْحَقِّ ۗذٰلِكَ يَوْمُ الْخُرُوْجِ ', 'Pada hari itulah mereka mendengar suara dahsyat dengan sebenar-benarnya. Itulah hari (ketika manusia) keluar (dari kubur).', '', 'https://everyayah.com/data/Alafasy_128kbps/050042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:43', 50, 43, 26, 520, 4673, 'اِنَّا نَحْنُ نُحْيٖ وَنُمِيْتُ وَاِلَيْنَا الْمَصِيْرُۙ', ' Sesungguhnya Kamilah yang menghidupkan dan mematikan dan kepada Kamilah kembalinya (seluruh makhluk).', '', 'https://everyayah.com/data/Alafasy_128kbps/050043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:44', 50, 44, 26, 520, 4674, 'يَوْمَ تَشَقَّقُ الْاَرْضُ عَنْهُمْ سِرَاعًا ۗذٰلِكَ حَشْرٌ عَلَيْنَا يَسِيْرٌ ', ' Pada hari itu bumi terbelah dengan mengeluarkan mereka, (kemudian mereka) bergegas (menuju Padang Mahsyar). Yang demikian itu adalah pengumpulan yang mudah bagi Kami.', '', 'https://everyayah.com/data/Alafasy_128kbps/050044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:45', 50, 45, 26, 520, 4675, 'نَحْنُ اَعْلَمُ بِمَا يَقُوْلُوْنَ وَمَآ اَنْتَ عَلَيْهِمْ بِجَبَّارٍۗ فَذَكِّرْ بِالْقُرْاٰنِ مَنْ يَّخَافُ وَعِيْدِ ࣖ ', ' Kami lebih mengetahui apa yang mereka katakan dan engkau (Nabi Muhammad) bukanlah seorang pemaksa terhadap mereka. Maka, berilah peringatan dengan Al-Qur’an kepada siapa pun yang takut pada ancaman-Ku.', '', 'https://everyayah.com/data/Alafasy_128kbps/050045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:1', 51, 1, 26, 520, 4676, ' وَالذّٰرِيٰتِ ذَرْوًاۙ', ' Demi (angin) yang menerbangkan debu,', '', 'https://everyayah.com/data/Alafasy_128kbps/051001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:2', 51, 2, 26, 520, 4677, 'فَالْحٰمِلٰتِ وِقْرًاۙ', ' demi (awan) yang mengandung muatan (hujan),', '', 'https://everyayah.com/data/Alafasy_128kbps/051002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:3', 51, 3, 26, 520, 4678, 'فَالْجٰرِيٰتِ يُسْرًاۙ', ' demi (kapal-kapal) yang melaju (di atas air) dengan mudah,', '', 'https://everyayah.com/data/Alafasy_128kbps/051003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:4', 51, 4, 26, 520, 4679, 'فَالْمُقَسِّمٰتِ اَمْرًاۙ', ' dan demi (malaikat-malaikat) yang membagi-bagi segala urusan,', '', 'https://everyayah.com/data/Alafasy_128kbps/051004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:5', 51, 5, 26, 520, 4680, 'اِنَّمَا تُوْعَدُوْنَ لَصَادِقٌۙ', ' sesungguhnya apa yang dijanjikan kepadamu pasti benar', '', 'https://everyayah.com/data/Alafasy_128kbps/051005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:6', 51, 6, 26, 520, 4681, 'وَّاِنَّ الدِّيْنَ لَوَاقِعٌۗ', 'dan sesungguhnya pembalasan pasti terjadi.', '', 'https://everyayah.com/data/Alafasy_128kbps/051006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:7', 51, 7, 26, 521, 4682, 'وَالسَّمَاۤءِ ذَاتِ الْحُبُكِۙ', '  Demi langit yang mempunyai jalan-jalan yang kukuh,700)', '700)Yang dimaksud dengan żātilḥubuk(jalan-jalan yang kukuh) adalah garis edar bintang, planet, dan benda-benda angkasa lainnya. Ada pula yang mengartikan żātilḥubukdengan ‘memiliki ciptaan yang bagus’, ‘memiliki hiasan bintang-bintang’, atau ‘memiliki bangunan yang kukuh’.', 'https://everyayah.com/data/Alafasy_128kbps/051007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:8', 51, 8, 26, 521, 4683, 'اِنَّكُمْ لَفِيْ قَوْلٍ مُّخْتَلِفٍۙ', 'sesungguhnya kamu benar-benar dalam keadaan berselisih.701)', '701)Maksudnya adalah perbedaan pendapat kaum musyrik tentang Nabi Muhammad saw. dan Al-Qur’an.', 'https://everyayah.com/data/Alafasy_128kbps/051008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:9', 51, 9, 26, 521, 4684, 'يُّؤْفَكُ عَنْهُ مَنْ اُفِكَۗ', ' Telah dijauhkan darinya (Al-Qur’an dan Rasul) orang yang dipalingkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/051009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:10', 51, 10, 26, 521, 4685, 'قُتِلَ الْخَرَّاصُوْنَۙ', ' Terkutuklah orang-orang yang banyak berdusta,', '', 'https://everyayah.com/data/Alafasy_128kbps/051010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:11', 51, 11, 26, 521, 4686, 'الَّذِيْنَ هُمْ فِيْ غَمْرَةٍ سَاهُوْنَۙ', '(yaitu) orang-orang yang terbenam (dalam kebodohan) lagi lalai (dari urusan akhirat)!', '', 'https://everyayah.com/data/Alafasy_128kbps/051011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:12', 51, 12, 26, 521, 4687, 'يَسْـَٔلُوْنَ اَيَّانَ يَوْمُ الدِّيْنِۗ', 'Mereka bertanya, “Kapankah hari Pembalasan itu?”', '', 'https://everyayah.com/data/Alafasy_128kbps/051012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:13', 51, 13, 26, 521, 4688, 'يَوْمَ هُمْ عَلَى النَّارِ يُفْتَنُوْنَ ', ' (Hari Pembalasan terjadi) pada hari (ketika) mereka diazab dalam api neraka.', '', 'https://everyayah.com/data/Alafasy_128kbps/051013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:14', 51, 14, 26, 521, 4689, 'ذُوْقُوْا فِتْنَتَكُمْۗ هٰذَا الَّذِيْ كُنْتُمْ بِهٖ تَسْتَعْجِلُوْنَ ', ' (Dikatakan kepada mereka,) “Rasakanlah azabmu! Inilah azab yang dahulu kamu minta agar disegerakan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/051014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:15', 51, 15, 26, 521, 4690, 'اِنَّ الْمُتَّقِيْنَ فِيْ جَنّٰتٍ وَّعُيُوْنٍۙ', ' Sesungguhnya orang-orang yang 
bertakwa berada dalam (surga yang penuh) taman-taman dan mata air.
', '', 'https://everyayah.com/data/Alafasy_128kbps/051015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:16', 51, 16, 26, 521, 4691, 'اٰخِذِيْنَ مَآ اٰتٰىهُمْ رَبُّهُمْ ۗ اِنَّهُمْ كَانُوْا قَبْلَ ذٰلِكَ مُحْسِنِيْنَۗ', ' (Di surga) mereka dapat mengambil apa saja yang dianugerahkan Tuhan kepada mereka. Sesungguhnya mereka sebelum itu (di dunia) adalah orang-orang yang berbuat kebaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/051016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:17', 51, 17, 26, 521, 4692, 'كَانُوْا قَلِيْلًا مِّنَ الَّيْلِ مَا يَهْجَعُوْنَ ', 'Mereka sedikit sekali tidur pada waktu malam;', '', 'https://everyayah.com/data/Alafasy_128kbps/051017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:18', 51, 18, 26, 521, 4693, 'وَبِالْاَسْحَارِ هُمْ يَسْتَغْفِرُوْنَ ', ' dan pada akhir malam mereka memohon ampunan (kepada Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/051018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:19', 51, 19, 26, 521, 4694, 'وَفِيْٓ اَمْوَالِهِمْ حَقٌّ لِّلسَّاۤىِٕلِ وَالْمَحْرُوْمِ ', ' Pada harta benda mereka ada hak bagi orang miskin yang meminta dan yang tidak meminta.', '', 'https://everyayah.com/data/Alafasy_128kbps/051019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:20', 51, 20, 26, 521, 4695, 'وَفِى الْاَرْضِ اٰيٰتٌ لِّلْمُوْقِنِيْنَۙ', ' Di bumi terdapat tanda-tanda (kebesaran Allah) bagi orang-orang yang yakin.', '', 'https://everyayah.com/data/Alafasy_128kbps/051020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:21', 51, 21, 26, 521, 4696, 'وَفِيْٓ اَنْفُسِكُمْ ۗ اَفَلَا تُبْصِرُوْنَ ', ' (Begitu juga ada tanda-tanda kebesaran-Nya) pada dirimu sendiri. Maka, apakah kamu tidak memperhatikan?', '', 'https://everyayah.com/data/Alafasy_128kbps/051021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:22', 51, 22, 26, 521, 4697, 'وَفِى السَّمَاۤءِ رِزْقُكُمْ وَمَا تُوْعَدُوْنَ ', ' Di langit terdapat pula (hujan yang menjadi sebab) rezekimu dan apa yang dijanjikan kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/051022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:23', 51, 23, 26, 521, 4698, 'فَوَرَبِّ السَّمَاۤءِ وَالْاَرْضِ اِنَّهٗ لَحَقٌّ مِّثْلَ مَآ اَنَّكُمْ تَنْطِقُوْنَ ࣖ', ' Maka, demi Tuhan langit dan bumi, sesungguhnya (apa yang dijanjikan kepadamu itu) pasti akan nyata seperti (halnya) kamu berucap.', '', 'https://everyayah.com/data/Alafasy_128kbps/051023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:24', 51, 24, 26, 521, 4699, 'هَلْ اَتٰىكَ حَدِيْثُ ضَيْفِ اِبْرٰهِيْمَ الْمُكْرَمِيْنَۘ ', ' Sudahkah sampai kepadamu (Nabi Muhammad) cerita tentang tamu Ibrahim (malaikat-malaikat) yang dimuliakan?', '', 'https://everyayah.com/data/Alafasy_128kbps/051024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:25', 51, 25, 26, 521, 4700, 'اِذْ دَخَلُوْا عَلَيْهِ فَقَالُوْا سَلٰمًا ۗقَالَ سَلٰمٌۚ قَوْمٌ مُّنْكَرُوْنَ ', '(Cerita itu bermula) ketika mereka masuk (bertamu) kepadanya, lalu mengucapkan, “Salam.” Ibrahim menjawab, “Salam.” (Mereka) adalah orang-orang yang belum dikenal.', '', 'https://everyayah.com/data/Alafasy_128kbps/051025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:26', 51, 26, 26, 521, 4701, 'فَرَاغَ اِلٰٓى اَهْلِهٖ فَجَاۤءَ بِعِجْلٍ سَمِيْنٍۙ', 'Kemudian, dia (Ibrahim) pergi diam-diam menemui keluarganya, lalu datang (kembali) membawa (daging) anak sapi gemuk (yang dibakar).', '', 'https://everyayah.com/data/Alafasy_128kbps/051026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:27', 51, 27, 26, 521, 4702, 'فَقَرَّبَهٗٓ اِلَيْهِمْۚ قَالَ اَلَا تَأْكُلُوْنَ ', 'Dia lalu menghidangkannya kepada mereka, (tetapi mereka tidak mau makan). Ibrahim berkata, “Mengapa kamu tidak makan?”', '', 'https://everyayah.com/data/Alafasy_128kbps/051027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:28', 51, 28, 26, 521, 4703, 'فَاَوْجَسَ مِنْهُمْ خِيْفَةً  ۗقَالُوْا لَا تَخَفْۗ وَبَشَّرُوْهُ بِغُلٰمٍ عَلِيْمٍ ', 'Dia (Ibrahim) menyimpan rasa takut terhadap mereka. Mereka berkata, “Janganlah takut!” Mereka memberi kabar gembira kepadanya dengan (akan kelahiran) seorang anak yang sangat berilmu (Ishaq).', '', 'https://everyayah.com/data/Alafasy_128kbps/051028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:29', 51, 29, 26, 521, 4704, 'فَاَقْبَلَتِ امْرَاَتُهٗ فِيْ صَرَّةٍ فَصَكَّتْ وَجْهَهَا وَقَالَتْ عَجُوْزٌ عَقِيْمٌ ', 'Istrinya datang sambil berteriak (terperanjat) lalu menepuk-nepuk wajahnya sendiri dan berkata, “(Aku ini) seorang perempuan tua yang mandul.”', '', 'https://everyayah.com/data/Alafasy_128kbps/051029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:30', 51, 30, 26, 521, 4705, 'قَالُوْا كَذٰلِكِۙ قَالَ رَبُّكِ ۗاِنَّهٗ هُوَ الْحَكِيْمُ الْعَلِيْمُ  ۔', 'Mereka berkata, “Demikianlah Tuhanmu berfirman. Sesungguhnya Dialah Yang Maha Bijaksana lagi Maha Mengetahui.”', '', 'https://everyayah.com/data/Alafasy_128kbps/051030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:31', 51, 31, 27, 522, 4706, '۞ قَالَ فَمَا خَطْبُكُمْ اَيُّهَا الْمُرْسَلُوْنَۚ  ', 'Dia (Ibrahim) bertanya, “Apa urusan pentingmu, wahai para utusan?”', '', 'https://everyayah.com/data/Alafasy_128kbps/051031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:32', 51, 32, 27, 522, 4707, 'قَالُوْآ اِنَّآ اُرْسِلْنَآ اِلٰى قَوْمٍ مُّجْرِمِيْنَۙ ', 'Mereka menjawab, “Sesungguhnya kami diutus kepada kaum yang berdosa (kaum Lut untuk menyiksanya)', '', 'https://everyayah.com/data/Alafasy_128kbps/051032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:33', 51, 33, 27, 522, 4708, 'لِنُرْسِلَ عَلَيْهِمْ حِجَارَةً مِّنْ طِيْنٍۙ', 'agar kami menimpa mereka dengan batu-batu yang berasal dari tanah liat', '', 'https://everyayah.com/data/Alafasy_128kbps/051033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:34', 51, 34, 27, 522, 4709, 'مُّسَوَّمَةً عِنْدَ رَبِّكَ لِلْمُسْرِفِيْنَ ', 'yang ditandai oleh Tuhanmu untuk (membinasakan) orang-orang yang melampaui batas.”', '', 'https://everyayah.com/data/Alafasy_128kbps/051034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:35', 51, 35, 27, 522, 4710, 'فَاَخْرَجْنَا مَنْ كَانَ فِيْهَا مِنَ الْمُؤْمِنِيْنَۚ ', 'Kami mengeluarkan orang-orang mukmin yang berada di dalamnya (negeri kaum Lut).', '', 'https://everyayah.com/data/Alafasy_128kbps/051035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:36', 51, 36, 27, 522, 4711, 'فَمَا وَجَدْنَا فِيْهَا غَيْرَ بَيْتٍ مِّنَ الْمُسْلِمِيْنَۚ  ', 'Kami tidak mendapati di dalamnya, kecuali sebuah rumah dari orang-orang muslim (Lut dan keluarganya).', '', 'https://everyayah.com/data/Alafasy_128kbps/051036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:37', 51, 37, 27, 522, 4712, 'وَتَرَكْنَا فِيْهَآ اٰيَةً لِّلَّذِيْنَ يَخَافُوْنَ الْعَذَابَ الْاَلِيْمَۗ ', 'Kami meninggalkan suatu tanda (kebesaran-Nya702) di (negeri) itu bagi orang-orang yang takut pada azab yang pedih.', '702) Menurut sebagian mufasir, yang dimaksud dengan tanda kebesaran-Nya adalah batu-batu bertumpuk-tumpuk yang digunakan untuk membinasakan kaum Lut. Ada pula yang mengatakan bahwayangdimaksudadalahsebuah telaga yang airnya hitam dan berbau busuk.', 'https://everyayah.com/data/Alafasy_128kbps/051037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:38', 51, 38, 27, 522, 4713, 'وَفِيْ مُوْسٰىٓ اِذْ اَرْسَلْنٰهُ اِلٰى فِرْعَوْنَ بِسُلْطٰنٍ مُّبِيْنٍ ', '(Begitu pula Kami meninggalkan) pada Musa (tanda-tanda kekuasaan Allah) ketika Kami mengutusnya kepada Fir‘aun dengan membawa mukjizat yang nyata.', '', 'https://everyayah.com/data/Alafasy_128kbps/051038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:39', 51, 39, 27, 522, 4714, 'فَتَوَلّٰى بِرُكْنِهٖ وَقَالَ سٰحِرٌ اَوْ مَجْنُوْنٌ', 'Kemudian, dia (Fir‘aun) bersama bala tentaranya berpaling dan (Fir‘aun) berkata, “(Dia adalah) seorang penyihir atau orang gila.”', '', 'https://everyayah.com/data/Alafasy_128kbps/051039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:40', 51, 40, 27, 522, 4715, 'فَاَخَذْنٰهُ وَجُنُوْدَهٗ فَنَبَذْنٰهُمْ فِى الْيَمِّ وَهُوَ مُلِيْمٌۗ  ', 'Maka, Kami menghukumnya beserta bala tentaranya, lalu Kami menenggelamkan mereka ke dalam laut dalam keadaan melakukan perbuatan yang tercela.', '', 'https://everyayah.com/data/Alafasy_128kbps/051040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:41', 51, 41, 27, 522, 4716, 'وَفِيْ عَادٍ اِذْ اَرْسَلْنَا عَلَيْهِمُ الرِّيْحَ الْعَقِيْمَۚ  ', '(Begitu pula Kami meninggalkan) pada (kaum) ‘Ad (tanda-tanda kekuasaan Allah) ketika Kami mengirim kepada mereka angin yang membinasakan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/051041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:42', 51, 42, 27, 522, 4717, 'مَا تَذَرُ مِنْ شَيْءٍ اَتَتْ عَلَيْهِ اِلَّا جَعَلَتْهُ كَالرَّمِيْمِۗ ', '(Angin) itu tidak meninggalkan apa pun pada semua yang dilandanya, kecuali menjadikannya bagai tulang yang hancur.', '', 'https://everyayah.com/data/Alafasy_128kbps/051042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:43', 51, 43, 27, 522, 4718, 'وَفِيْ ثَمُوْدَ اِذْ قِيْلَ لَهُمْ تَمَتَّعُوْا حَتّٰى حِيْنٍ ', '(Begitu pula Kami meninggalkan) pada (kaum) Samud (tanda-tanda kekuasaan Allah) ketika dikatakan kepada mereka, “Bersenang-senanglah kamu sampai waktu yang ditentukan!”', '', 'https://everyayah.com/data/Alafasy_128kbps/051043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:44', 51, 44, 27, 522, 4719, 'فَعَتَوْا عَنْ اَمْرِ رَبِّهِمْ فَاَخَذَتْهُمُ الصّٰعِقَةُ وَهُمْ يَنْظُرُوْنَ', 'Lalu, mereka bersikap angkuh terhadap perintah Tuhannya. Maka, mereka disambar petir sementara mereka menyaksikan(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/051044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:45', 51, 45, 27, 522, 4720, 'فَمَا اسْتَطَاعُوْا مِنْ قِيَامٍ وَّمَا كَانُوْا مُنْتَصِرِيْنَۙ ', 'Mereka sama sekali tidak mampu bangun dan tidak pula mendapat pertolongan.', '', 'https://everyayah.com/data/Alafasy_128kbps/051045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:46', 51, 46, 27, 522, 4721, 'وَقَوْمَ نُوْحٍ مِّنْ قَبْلُ ۗ اِنَّهُمْ كَانُوْا قَوْمًا فٰسِقِيْنَ ࣖ ', 'Sebelum itu (Kami telah membinasakan) kaum Nuh. Sesungguhnya mereka adalah kaum fasik.', '', 'https://everyayah.com/data/Alafasy_128kbps/051046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:47', 51, 47, 27, 522, 4722, 'وَالسَّمَاۤءَ بَنَيْنٰهَا بِاَيْىدٍ وَّاِنَّا لَمُوْسِعُوْنَ', 'Langit Kami bangun dengan tangan (kekuatan Kami) dan sesungguhnya Kami benar-benar meluaskan(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/051047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:48', 51, 48, 27, 522, 4723, 'وَالْاَرْضَ فَرَشْنٰهَا فَنِعْمَ الْمٰهِدُوْنَ', 'Bumi Kami hamparkan. (Kami adalah) sebaik-baik Zat yang menghamparkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/051048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:49', 51, 49, 27, 522, 4724, 'وَمِنْ كُلِّ شَيْءٍ خَلَقْنَا زَوْجَيْنِ لَعَلَّكُمْ تَذَكَّرُوْنَ', 'Segala sesuatu Kami ciptakan berpasang-pasangan agar kamu mengingat (kebesaran Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/051049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:50', 51, 50, 27, 522, 4725, 'فَفِرُّوْٓا اِلَى اللّٰهِ ۗاِنِّيْ لَكُمْ مِّنْهُ نَذِيْرٌ مُّبِيْنٌۚ  ', 'Maka, (katakanlah kepada mereka, wahai Nabi Muhammad,) “Bersegeralah kembali (taat) kepada Allah. Sesungguhnya aku adalah seorang pemberi peringatan yang jelas dari-Nya untukmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/051050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:51', 51, 51, 27, 522, 4726, 'وَلَا تَجْعَلُوْا مَعَ اللّٰهِ اِلٰهًا اٰخَرَۗ اِنِّيْ لَكُمْ مِّنْهُ نَذِيْرٌ مُّبِيْنٌ', 'Janganlah kamu mengadakan tuhan lain bersama Allah. Sesungguhnya aku adalah seorang pemberi peringatan yang jelas dari Allah untukmu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/051051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:52', 51, 52, 27, 523, 4727, 'كَذٰلِكَ مَآ اَتَى الَّذِيْنَ مِنْ قَبْلِهِمْ مِّنْ رَّسُوْلٍ اِلَّا قَالُوْا سَاحِرٌ اَوْ مَجْنُوْنٌ', 'Demikianlah setiap kali seorang rasul datang kepada orang-orang sebelumnya, mereka pasti mengatakan, “(Dia itu adalah) penyihir atau orang gila.”', '', 'https://everyayah.com/data/Alafasy_128kbps/051052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:53', 51, 53, 27, 523, 4728, 'اَتَوَاصَوْا بِهٖۚ بَلْ هُمْ قَوْمٌ طَاغُوْنَۚ ', 'Apakah mereka saling menasihati tentang (apa yang dikatakan) itu? (Tidak!) Sebaliknya, mereka adalah kaum yang melampaui batas.', '', 'https://everyayah.com/data/Alafasy_128kbps/051053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:54', 51, 54, 27, 523, 4729, 'فَتَوَلَّ عَنْهُمْ فَمَآ اَنْتَ بِمَلُوْمٍ  ', 'Berpalinglah dari mereka, maka engkau sama sekali bukan orang yang tercela.', '', 'https://everyayah.com/data/Alafasy_128kbps/051054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:55', 51, 55, 27, 523, 4730, 'وَذَكِّرْ فَاِنَّ الذِّكْرٰى تَنْفَعُ الْمُؤْمِنِيْنَ ', 'Teruslah memberi peringatan karena sesungguhnya peringatan itu bermanfaat bagi orang-orang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/051055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:56', 51, 56, 27, 523, 4731, 'وَمَا خَلَقْتُ الْجِنَّ وَالْاِنْسَ اِلَّا لِيَعْبُدُوْنِ', 'Tidaklah Aku menciptakan jin dan manusia kecuali untuk beribadah kepada-Ku.', '', 'https://everyayah.com/data/Alafasy_128kbps/051056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:57', 51, 57, 27, 523, 4732, 'مَآ اُرِيْدُ مِنْهُمْ مِّنْ رِّزْقٍ وَّمَآ اُرِيْدُ اَنْ يُّطْعِمُوْنِ ', 'Aku tidak menghendaki rezeki sedikit pun dari mereka dan tidak menghendaki agar mereka memberi makan kepada-Ku.', '', 'https://everyayah.com/data/Alafasy_128kbps/051057.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:58', 51, 58, 27, 523, 4733, 'اِنَّ اللّٰهَ هُوَ الرَّزَّاقُ ذُو الْقُوَّةِ الْمَتِيْنُ ', 'Sesungguhnya Allahlah Maha Pemberi Rezeki yang mempunyai kekuatan lagi sangat kukuh.', '', 'https://everyayah.com/data/Alafasy_128kbps/051058.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:59', 51, 59, 27, 523, 4734, 'فَاِنَّ لِلَّذِيْنَ ظَلَمُوْا ذَنُوْبًا مِّثْلَ ذَنُوْبِ اَصْحٰبِهِمْ فَلَا يَسْتَعْجِلُوْنِ', 'Sesungguhnya orang-orang yang zalim mendapatkan bagian (azab) seperti bagian teman-teman mereka (dahulu). Maka, janganlah mereka meminta kepada-Ku untuk menyegerakan(-nya).
', '', 'https://everyayah.com/data/Alafasy_128kbps/051059.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('51:60', 51, 60, 27, 523, 4735, 'فَوَيْلٌ لِّلَّذِيْنَ كَفَرُوْا مِنْ يَّوْمِهِمُ الَّذِيْ يُوْعَدُوْنَ ࣖ ', 'Celakalah orang-orang yang kufur pada hari yang telah dijanjikan kepada mereka (hari Kiamat).', '', 'https://everyayah.com/data/Alafasy_128kbps/051060.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:1', 52, 1, 27, 523, 4736, 'وَالطُّوْرِۙ  ', 'Demi gunung (Sinai),', '', 'https://everyayah.com/data/Alafasy_128kbps/052001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:2', 52, 2, 27, 523, 4737, 'وَكِتٰبٍ مَّسْطُوْرٍۙ  ', 'demi Kitab yang ditulis', '', 'https://everyayah.com/data/Alafasy_128kbps/052002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:3', 52, 3, 27, 523, 4738, 'فِيْ رَقٍّ مَّنْشُوْرٍۙ  ', 'pada lembaran yang terbuka,', '', 'https://everyayah.com/data/Alafasy_128kbps/052003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:4', 52, 4, 27, 523, 4739, 'وَّالْبَيْتِ الْمَعْمُوْرِۙ  ', 'demi Baitulmakmur,703)', '703) Menurut riwayat al-Bukhari dan Muslim, Baitulmakmur adalah rumah di langit ketujuh yang senantiasa diramaikan oleh 70.000 malaikat yang beribadah salat.', 'https://everyayah.com/data/Alafasy_128kbps/052004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:5', 52, 5, 27, 523, 4740, 'وَالسَّقْفِ الْمَرْفُوْعِۙ  ', ' demi atap yang ditinggikan (langit),', '', 'https://everyayah.com/data/Alafasy_128kbps/052005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:6', 52, 6, 27, 523, 4741, 'وَالْبَحْرِ الْمَسْجُوْرِۙ ', 'dan demi lautan yang dipanaskan (di dalamnya ada api),', '', 'https://everyayah.com/data/Alafasy_128kbps/052006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:7', 52, 7, 27, 523, 4742, 'اِنَّ عَذَابَ رَبِّكَ لَوَاقِعٌۙ  ', 'sesungguhnya azab Tuhanmu pasti terjadi.', '', 'https://everyayah.com/data/Alafasy_128kbps/052007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:8', 52, 8, 27, 523, 4743, 'مَّا لَهٗ مِنْ دَافِعٍۙ  ', ' Tidak ada sesuatu pun yang dapat menolaknya.', '', 'https://everyayah.com/data/Alafasy_128kbps/052008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:9', 52, 9, 27, 523, 4744, 'يَّوْمَ تَمُوْرُ السَّمَاۤءُ مَوْرًاۙ ', '(Azab Tuhanmu terjadi) pada hari (ketika) langit berguncang sekeras-kerasnya', '', 'https://everyayah.com/data/Alafasy_128kbps/052009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:10', 52, 10, 27, 523, 4745, 'وَّتَسِيْرُ الْجِبَالُ سَيْرًاۗ  ', ' dan gunung-gunung bergerak dengan dahsyat.', '', 'https://everyayah.com/data/Alafasy_128kbps/052010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:11', 52, 11, 27, 523, 4746, 'فَوَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَۙ  ', 'Maka, pada hari itu celakalah orang-orang yang mendustakan,', '', 'https://everyayah.com/data/Alafasy_128kbps/052011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:12', 52, 12, 27, 523, 4747, 'الَّذِيْنَ هُمْ فِيْ خَوْضٍ يَّلْعَبُوْنَۘ  ', ' (yaitu) orang-orang yang bermain-main dalam kebatilan (perbuatan dosa).', '', 'https://everyayah.com/data/Alafasy_128kbps/052012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:13', 52, 13, 27, 523, 4748, 'يَوْمَ يُدَعُّوْنَ اِلٰى نَارِ جَهَنَّمَ دَعًّاۗ', ' (Azab Tuhanmu terjadi) pada hari (ketika) mereka dicampakkan ke neraka Jahanam dengan sekuat-kuatnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/052013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:14', 52, 14, 27, 523, 4749, 'هٰذِهِ النَّارُ الَّتِيْ كُنْتُمْ بِهَا تُكَذِّبُوْنَ ', '(Dikatakan kepada mereka,) “Inilah neraka yang dahulu kamu dustakan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/052014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:15', 52, 15, 27, 524, 4750, 'اَفَسِحْرٌ هٰذَآ اَمْ اَنْتُمْ لَا تُبْصِرُوْنَ ', 'Apakah ini sihir? Ataukah kamu tidak melihat?', '', 'https://everyayah.com/data/Alafasy_128kbps/052015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:16', 52, 16, 27, 524, 4751, 'اِصْلَوْهَا فَاصْبِرُوْٓا اَوْ لَا تَصْبِرُوْاۚ سَوَاۤءٌ عَلَيْكُمْۗ  اِنَّمَا تُجْزَوْنَ مَا كُنْتُمْ تَعْمَلُوْنَ ', 'Masuklah ke dalamnya (dan rasakan panas apinya)! Baik kamu bersabar atau tidak, sama saja (tidak ada manfaatnya)bagimu. Sesungguhnya kamu hanya diberi balasan atas apa yang telah kamu kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/052016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:17', 52, 17, 27, 524, 4752, 'اِنَّ الْمُتَّقِيْنَ فِيْ جَنّٰتٍ وَّنَعِيْمٍۙ  ', 'Sesungguhnya orang-orang yang bertakwa berada dalam surga dan kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/052017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:18', 52, 18, 27, 524, 4753, 'فٰكِهِيْنَ بِمَآ اٰتٰىهُمْ رَبُّهُمْۚ وَوَقٰىهُمْ رَبُّهُمْ عَذَابَ الْجَحِيْمِ', 'Mereka bersuka ria dengan apa yang Tuhan anugerahkan kepada mereka. Tuhan menjaga mereka dari azab (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/052018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:19', 52, 19, 27, 524, 4754, 'كُلُوْا وَاشْرَبُوْا هَنِيْۤـًٔا ۢبِمَا كُنْتُمْ تَعْمَلُوْنَۙ  ', ' (Dikatakan kepada mereka,) “Makan dan minumlah dengan nikmat sebagai balasan dari apa yang telah kamu kerjakan!”', '', 'https://everyayah.com/data/Alafasy_128kbps/052019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:20', 52, 20, 27, 524, 4755, 'مُتَّكِـِٕيْنَ عَلٰى سُرُرٍ مَّصْفُوْفَةٍۚ وَزَوَّجْنٰهُمْ بِحُوْرٍ عِيْنٍ', ' Mereka bertelekan di atas dipan-dipan yang tersusun dan Kami menganugerahkan kepada mereka pasangan, yaitu bidadari yang bermata indah.', '', 'https://everyayah.com/data/Alafasy_128kbps/052020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:21', 52, 21, 27, 524, 4756, 'وَالَّذِيْنَ اٰمَنُوْا وَاتَّبَعَتْهُمْ ذُرِّيَّتُهُمْ بِاِيْمَانٍ اَلْحَقْنَا بِهِمْ ذُرِّيَّتَهُمْ وَمَآ اَلَتْنٰهُمْ مِّنْ عَمَلِهِمْ مِّنْ شَيْءٍۗ  كُلُّ امْرِئٍ ۢبِمَا كَسَبَ رَهِيْنٌ ', 'Orang-orang yang beriman dan anak cucunya mengikuti mereka dalam keimanan, Kami akan mengumpulkan anak cucunya itu dengan mereka (di dalam surga). Kami tidak mengurangi sedikit pun pahala amal (kebajikan) mereka. Setiap orang terikat dengan apa yang dikerjakannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/052021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:22', 52, 22, 27, 524, 4757, 'وَاَمْدَدْنٰهُمْ بِفَاكِهَةٍ وَّلَحْمٍ مِّمَّا يَشْتَهُوْنَ ', ' Kami menganugerahkan kepada mereka tambahan (kenikmatan) berupa buah-buahan dan daging dari segala jenis yang mereka inginkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/052022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:23', 52, 23, 27, 524, 4758, 'يَتَنَازَعُوْنَ فِيْهَا كَأْسًا لَّا لَغْوٌ فِيْهَا وَلَا تَأْثِيْمٌ ', ' Di dalam (surga) itu mereka saling mengulurkan gelas (yang isinya) tidak (menimbulkan) ucapan atau sikap yang tidak berfaedah dan tidak pula (menimbulkan) perbuatan dosa.', '', 'https://everyayah.com/data/Alafasy_128kbps/052023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:24', 52, 24, 27, 524, 4759, '۞ وَيَطُوْفُ عَلَيْهِمْ غِلْمَانٌ لَّهُمْ كَاَنَّهُمْ لُؤْلُؤٌ مَّكْنُوْنٌۚ  ', ' Di sekitar mereka ada anak-anak muda belia berkeliling untuk (melayani) mereka, seakan-akan (anak muda belia) itu bagaikan mutiara yang tersimpan.', '', 'https://everyayah.com/data/Alafasy_128kbps/052024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:25', 52, 25, 27, 524, 4760, 'وَاَقْبَلَ بَعْضُهُمْ عَلٰى بَعْضٍ يَّتَسَاۤءَلُوْنَ ', ' Sebagian mereka menghadap kepada sebagian yang lain saling bertegur sapa.', '', 'https://everyayah.com/data/Alafasy_128kbps/052025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:26', 52, 26, 27, 524, 4761, 'قَالُوْٓا اِنَّا كُنَّا قَبْلُ فِيْٓ اَهْلِنَا مُشْفِقِيْنَ ', 'Mereka berkata, “Sesungguhnya kami dahulu, sewaktu berada di tengah-tengah keluarga kami, adalah orang yang takut (ditimpa azab Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/052026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:27', 52, 27, 27, 524, 4762, 'فَمَنَّ اللّٰهُ عَلَيْنَا وَوَقٰىنَا عَذَابَ السَّمُوْمِ ', ' Allah menganugerahkan karunia kepada kami dan menjaga kami dari azab neraka.', '', 'https://everyayah.com/data/Alafasy_128kbps/052027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:28', 52, 28, 27, 524, 4763, 'اِنَّا كُنَّا مِنْ قَبْلُ نَدْعُوْهُۗ اِنَّهٗ هُوَ الْبَرُّ الرَّحِيْمُ ࣖ', ' Sesungguhnya kami menyembah-Nya sejak dahulu. Sesungguhnya hanya Dialah Yang Maha Luas kebajikan-Nya lagi Maha Penyayang.”', '', 'https://everyayah.com/data/Alafasy_128kbps/052028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:29', 52, 29, 27, 524, 4764, 'فَذَكِّرْ فَمَآ اَنْتَ بِنِعْمَتِ رَبِّكَ بِكَاهِنٍ وَّلَا مَجْنُوْنٍۗ ', '(Wahai Nabi Muhammad,) teruslah menyampaikan peringatan karena berkat nikmat Tuhanmulah, engkau bukan seorang tukang tenung dan bukan pula orang gila!', '', 'https://everyayah.com/data/Alafasy_128kbps/052029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:30', 52, 30, 27, 524, 4765, 'اَمْ يَقُوْلُوْنَ شَاعِرٌ نَّتَرَبَّصُ بِهٖ رَيْبَ الْمَنُوْنِ ', ' Bahkan, mereka (orang musyrik Makkah) berkata, “Dia (Nabi Muhammad) adalah seorang penyair yang kami tunggu-tunggu kecelakaan menimpanya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/052030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:31', 52, 31, 27, 524, 4766, 'قُلْ تَرَبَّصُوْا فَاِنِّيْ مَعَكُمْ مِّنَ الْمُتَرَبِّصِيْنَۗ  ', ' Katakanlah (Nabi Muhammad), “Tunggulah! Sesungguhnya aku pun termasuk orang yang sedang menunggu bersamamu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/052031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:32', 52, 32, 27, 525, 4767, 'اَمْ تَأْمُرُهُمْ اَحْلَامُهُمْ بِهٰذَآ اَمْ هُمْ قَوْمٌ طَاغُوْنَۚ ', ' Apakah mereka diperintah oleh pikiran-pikiran mereka untuk mengucapkan (tuduhan-tuduhan) ini atau apakah mereka kaum yang melampaui batas?', '', 'https://everyayah.com/data/Alafasy_128kbps/052032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:33', 52, 33, 27, 525, 4768, 'اَمْ يَقُوْلُوْنَ تَقَوَّلَهٗۚ بَلْ لَّا يُؤْمِنُوْنَۚ ', 'Bahkan, apakah mereka (juga) berkata, “Dia (Nabi Muhammad) mereka-rekanya?” Tidak! Merekalah yang tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/052033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:34', 52, 34, 27, 525, 4769, 'فَلْيَأْتُوْا بِحَدِيْثٍ مِّثْلِهٖٓ اِنْ كَانُوْا صٰدِقِيْنَۗ  ', ' Cobalah mereka membuat yang semisal dengannya (Al-Qur’an) jika mereka orang-orang benar.', '', 'https://everyayah.com/data/Alafasy_128kbps/052034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:35', 52, 35, 27, 525, 4770, 'اَمْ خُلِقُوْا مِنْ غَيْرِ شَيْءٍ اَمْ هُمُ الْخٰلِقُوْنَۗ  ', 'Apakah mereka tercipta tanpa asal-usul ataukah mereka menciptakan (diri mereka sendiri)?', '', 'https://everyayah.com/data/Alafasy_128kbps/052035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:36', 52, 36, 27, 525, 4771, 'اَمْ خَلَقُوا السَّمٰوٰتِ وَالْاَرْضَۚ بَلْ لَّا يُوْقِنُوْنَۗ  ', ' Apakah mereka menciptakan langit dan bumi? Sebenarnya mereka tidak meyakini (apa yang mereka katakan).', '', 'https://everyayah.com/data/Alafasy_128kbps/052036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:37', 52, 37, 27, 525, 4772, 'اَمْ عِنْدَهُمْ خَزَاۤىِٕنُ رَبِّكَ اَمْ هُمُ الْمُصَۣيْطِرُوْنَۗ  ', 'Apakah di sisi mereka ada perbendaharaan Tuhanmu ataukah mereka yang berkuasa?', '', 'https://everyayah.com/data/Alafasy_128kbps/052037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:38', 52, 38, 27, 525, 4773, 'اَمْ لَهُمْ سُلَّمٌ يَّسْتَمِعُوْنَ فِيْهِۚ فَلْيَأْتِ مُسْتَمِعُهُمْ بِسُلْطٰنٍ مُّبِيْنٍۗ  ', ' Apakah mereka mempunyai tangga (ke langit) untuk mendengarkan (hal-hal yang gaib)? Hendaklah orang yang mendengarkan di antara mereka itu datang membawa keterangan yang nyata.', '', 'https://everyayah.com/data/Alafasy_128kbps/052038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:39', 52, 39, 27, 525, 4774, 'اَمْ لَهُ الْبَنٰتُ وَلَكُمُ الْبَنُوْنَۗ  ', 'Apakah (pantas) bagi-Nya anak-anak perempuan, sedangkan untuk kamu anak-anak laki-laki?', '', 'https://everyayah.com/data/Alafasy_128kbps/052039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:40', 52, 40, 27, 525, 4775, 'اَمْ تَسْـَٔلُهُمْ اَجْرًا فَهُمْ مِّنْ مَّغْرَمٍ مُّثْقَلُوْنَۗ  ', ' Apakah engkau (Nabi Muhammad) meminta imbalan kepada mereka sehingga mereka dibebani dengan utang?', '', 'https://everyayah.com/data/Alafasy_128kbps/052040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:41', 52, 41, 27, 525, 4776, 'اَمْ عِنْدَهُمُ الْغَيْبُ فَهُمْ يَكْتُبُوْنَۗ ', 'Apakah mereka mempunyai (pengetahuan) tentang yang gaib, lalu mereka menuliskannya?', '', 'https://everyayah.com/data/Alafasy_128kbps/052041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:42', 52, 42, 27, 525, 4777, 'اَمْ يُرِيْدُوْنَ كَيْدًاۗ فَالَّذِيْنَ كَفَرُوْا هُمُ الْمَكِيْدُوْنَۗ  ', ' Apakah mereka hendak melakukan tipu daya? Justru orang-orang yang kufur itulah yang terkena tipu daya.', '', 'https://everyayah.com/data/Alafasy_128kbps/052042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:43', 52, 43, 27, 525, 4778, 'اَمْ لَهُمْ اِلٰهٌ غَيْرُ اللّٰهِ ۗسُبْحٰنَ اللّٰهِ عَمَّا يُشْرِكُوْنَ  ', ' Apakah mereka mempunyai tuhan selain Allah? Maha Suci Allah dari apa yang mereka persekutukan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/052043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:44', 52, 44, 27, 525, 4779, 'وَاِنْ يَّرَوْا كِسْفًا مِّنَ السَّمَاۤءِ سَاقِطًا يَّقُوْلُوْا سَحَابٌ مَّرْكُوْمٌ ', 'Jika mereka melihat gumpalan-gumpalan awan berjatuhan dari langit, mereka berkata, “Itu adalah awan yang bertumpuk-tumpuk (yang akan menurunkan hujan).”', '', 'https://everyayah.com/data/Alafasy_128kbps/052044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:45', 52, 45, 27, 525, 4780, 'فَذَرْهُمْ حَتّٰى يُلٰقُوْا يَوْمَهُمُ الَّذِيْ فِيْهِ يُصْعَقُوْنَۙ  ', 'Biarkanlah mereka (dalam kesesatan) hingga mereka menemui hari (yang dijanjikan kepada) mereka yang pada hari itu mereka dibinasakan,', '', 'https://everyayah.com/data/Alafasy_128kbps/052045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:46', 52, 46, 27, 525, 4781, 'يَوْمَ لَا يُغْنِيْ عَنْهُمْ كَيْدُهُمْ شَيْـًٔا وَّلَا هُمْ يُنْصَرُوْنَۗ  ', ' (yaitu) pada hari (ketika) tipu daya mereka tidak berguna sedikit pun bagi mereka dan mereka tidak akan diberi pertolongan.', '', 'https://everyayah.com/data/Alafasy_128kbps/052046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:47', 52, 47, 27, 525, 4782, 'وَاِنَّ لِلَّذِيْنَ ظَلَمُوْا عَذَابًا دُوْنَ ذٰلِكَ وَلٰكِنَّ اَكْثَرَهُمْ لَا يَعْلَمُوْنَ ', ' Sesungguhnya bagi orang-orang yang zalim ada azab selain itu, tetapi kebanyakan mereka tidak mengetahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/052047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:48', 52, 48, 27, 525, 4783, 'وَاصْبِرْ لِحُكْمِ رَبِّكَ فَاِنَّكَ بِاَعْيُنِنَا وَسَبِّحْ بِحَمْدِ رَبِّكَ حِيْنَ تَقُوْمُۙ  ', ' Bersabarlah (Nabi Muhammad) menunggu ketetapan Tuhanmu karena sesungguhnya engkau berada dalam pengawasan Kami! Bertasbihlah seraya bertahmid (memuji) Tuhanmu ketika engkau bangun!', '', 'https://everyayah.com/data/Alafasy_128kbps/052048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('52:49', 52, 49, 27, 525, 4784, 'وَمِنَ الَّيْلِ فَسَبِّحْهُ وَاِدْبَارَ النُّجُوْمِ ࣖ', ' Bertasbihlah kepada-Nya pada sebagian malam dan pada waktu terbenamnya bintang-bintang (waktu fajar).', '', 'https://everyayah.com/data/Alafasy_128kbps/052049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:1', 53, 1, 27, 526, 4785, 'وَالنَّجْمِ اِذَا هَوٰىۙ ', ' Demi bintang ketika terbenam,', '', 'https://everyayah.com/data/Alafasy_128kbps/053001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:2', 53, 2, 27, 526, 4786, 'مَا ضَلَّ صَاحِبُكُمْ وَمَا غَوٰىۚ ', 'kawanmu (Nabi Muhammad) tidak sesat, tidak keliru,', '', 'https://everyayah.com/data/Alafasy_128kbps/053002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:3', 53, 3, 27, 526, 4787, 'وَمَا يَنْطِقُ عَنِ الْهَوٰى', ' dan tidak pula berucap (tentang Al-Qur’an dan penjelasannya) berdasarkan hawa nafsu(-nya). ', '', 'https://everyayah.com/data/Alafasy_128kbps/053003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:4', 53, 4, 27, 526, 4788, 'اِنْ هُوَ اِلَّا وَحْيٌ يُّوْحٰىۙ ', ' Ia (Al-Qur’an itu) tidak lain, kecuali wahyu yang disampaikan (kepadanya)', '', 'https://everyayah.com/data/Alafasy_128kbps/053004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:5', 53, 5, 27, 526, 4789, 'عَلَّمَهٗ شَدِيْدُ الْقُوٰىۙ ', ' yang diajarkan kepadanya oleh (malaikat) yang sangat kuat (Jibril)', '', 'https://everyayah.com/data/Alafasy_128kbps/053005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:6', 53, 6, 27, 526, 4790, 'ذُوْ مِرَّةٍۗ فَاسْتَوٰىۙ ', ' lagi mempunyai keteguhan. Lalu, ia (Jibril) menampakkan diri dengan rupa yang asli', '', 'https://everyayah.com/data/Alafasy_128kbps/053006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:7', 53, 7, 27, 526, 4791, 'وَهُوَ بِالْاُفُقِ الْاَعْلٰىۗ ', ' ketika dia berada di ufuk yang tinggi.', '', 'https://everyayah.com/data/Alafasy_128kbps/053007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:8', 53, 8, 27, 526, 4792, 'ثُمَّ دَنَا فَتَدَلّٰىۙ  ', ' Dia kemudian mendekat (kepada Nabi Muhammad), lalu bertambah dekat,', '', 'https://everyayah.com/data/Alafasy_128kbps/053008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:9', 53, 9, 27, 526, 4793, 'فَكَانَ قَابَ قَوْسَيْنِ اَوْ اَدْنٰىۚ', 'sehingga jaraknya (sekitar) dua busur panah atau lebih dekat (lagi).', '', 'https://everyayah.com/data/Alafasy_128kbps/053009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:10', 53, 10, 27, 526, 4794, 'فَاَوْحٰىٓ اِلٰى عَبْدِهٖ مَآ اَوْحٰىۗ', ' Lalu, dia (Jibril) menyampaikan wahyu kepada hamba-Nya (Nabi Muhammad) apa yang Dia wahyukan.', '', 'https://everyayah.com/data/Alafasy_128kbps/053010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:11', 53, 11, 27, 526, 4795, 'مَا كَذَبَ الْفُؤَادُ مَا رَاٰى', 'Hatinya tidak mendustakan apa yang telah dilihatnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/053011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:12', 53, 12, 27, 526, 4796, 'اَفَتُمٰرُوْنَهٗ عَلٰى مَا يَرٰى ', ' Apakah kamu (kaum musyrik Makkah) hendak membantahnya (Nabi Muhammad) tentang apa yang dilihatnya itu (Jibril)?', '', 'https://everyayah.com/data/Alafasy_128kbps/053012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:13', 53, 13, 27, 526, 4797, 'وَلَقَدْ رَاٰهُ نَزْلَةً اُخْرٰىۙ', ' Sungguh, dia (Nabi Muhammad) benar-benar telah melihatnya (dalam rupa yang asli) pada waktu yang lain,', '', 'https://everyayah.com/data/Alafasy_128kbps/053013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:14', 53, 14, 27, 526, 4798, 'عِنْدَ سِدْرَةِ الْمُنْتَهٰى ', '(yaitu ketika) di Sidratulmuntaha.', '', 'https://everyayah.com/data/Alafasy_128kbps/053014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:15', 53, 15, 27, 526, 4799, 'عِنْدَهَا جَنَّةُ الْمَأْوٰىۗ  ', ' Di dekatnya ada surga tempat tinggal.', '', 'https://everyayah.com/data/Alafasy_128kbps/053015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('53:16', 53, 16, 27, 526, 4800, 'اِذْ يَغْشَى السِّدْرَةَ مَا يَغْشٰىۙ ', ' (Nabi Muhammad melihat Jibril) ketika Sidratulmuntaha dilingkupi oleh sesuatu yang melingkupinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/053016.mp3');
PRAGMA foreign_keys = ON;
